// heart.js - 烟花告白页面JavaScript

// 配置常量
const CONFIG = {
    PARTICLE: {
        MAX_COUNT: 2000,
        BASE_SIZE: 2,
        HEART_SIZE: 3,
        LAUNCHER_COUNT: 20,
        GRAVITY: 0.05,
        RESISTANCE: 0.85,
        BASE_SPEED: 1.2,
        EXPLOSION_SPEED: 2.5
    },
    HEART: {
        BASE_SIZE: 15,
        EXPLOSION_SIZE: 20
    },
    TEXT: {
        FONT: 'bold 72px "Microsoft YaHei"',
        SAMPLE_INTERVAL: 8
    },
    STAR: {
        COUNT: 150,
        OPACITY_SPEED: 0.02
    },
    COLORS: [
        '#ff4081', // 粉色
        '#03a9f4', // 蓝色
        '#ffeb3b'  // 黄色
    ]
};

// 初始化画布
const canvas = document.getElementById('canvas');
const ctx = canvas.getContext('2d');
let [width, height] = [window.innerWidth, window.innerHeight];
[canvas.width, canvas.height] = [width, height];

// 音效系统
class SoundSystem {
    constructor() {
        this.enabled = false;
        this.audioContext = null;
        this.oscillators = new Map();

        try {
            this.audioContext = new (window.AudioContext || window.webkitAudioContext)();
            this.enabled = true;
        } catch (e) {
            console.warn('音频API不支持:', e);
        }

        this.toggleButton = document.getElementById('soundToggle');
        this.toggleButton.addEventListener('click', () => this.toggle());
    }

    toggle() {
        this.enabled = !this.enabled;
        this.toggleButton.textContent = this.enabled ? '🔊' : '🔇';

        if (this.enabled && this.audioContext && this.audioContext.state === 'suspended') {
            this.audioContext.resume();
        }

        if (!this.enabled) {
            this.stopAll();
        }
    }

    playTone(frequency, duration = 0.5, type = 'sine') {
        if (!this.enabled || !this.audioContext) return;

        const oscillator = this.audioContext.createOscillator();
        const gainNode = this.audioContext.createGain();

        oscillator.connect(gainNode);
        gainNode.connect(this.audioContext.destination);

        oscillator.frequency.value = frequency;
        oscillator.type = type;

        gainNode.gain.setValueAtTime(0.3, this.audioContext.currentTime);
        gainNode.gain.exponentialRampToValueAtTime(0.01, this.audioContext.currentTime + duration);

        oscillator.start(this.audioContext.currentTime);
        oscillator.stop(this.audioContext.currentTime + duration);

        const id = Symbol();
        this.oscillators.set(id, oscillator);

        oscillator.onended = () => {
            this.oscillators.delete(id);
        };
    }

