        setTimeout(() => {
            btn.innerHTML = originalText;
        }, 2000);
    },

    hideInputBox() {
        const inputBox = document.querySelector('.input-box');
        inputBox.classList.add('hidden');
        setTimeout(() => { inputBox.style.display = 'none'; }, 1000);
    },

    showMessage(name, duration = 3000) {
